// 교육용 빅뱅 시뮬레이션 - 실시간 물리 시뮬레이션 기반 4단계 진화 과정
import * as THREE from "three";

/**
 * 1️⃣ 쿼크-글루온 플라즈마 단계 (2초)
 * 50만 개의 입자가 급속으로 움직이고, 냉각 효과를 통해 속도 감소
 */
export function createQuarkGluonPlasma(numParticles = 500000) {
  const group = new THREE.Group();

  // 50만 개의 고에너지 입자
  const geometry = new THREE.BufferGeometry();
  const positions = new Float32Array(numParticles * 3);
  const colors = new Float32Array(numParticles * 3);
  const velocities = new Float32Array(numParticles * 3);

  // 입자 타입: 0=업쿼크(빨강), 1=다운쿼크(초록), 2=스트레인지(파랑), 3=글루온(노랑)
  const types = new Uint8Array(numParticles);
  for (let i = 0; i < numParticles; i++) {
    // 구 내에 균등 분포
    const r = Math.random() * 400;
    const theta = Math.random() * Math.PI * 2;
    const phi = Math.random() * Math.PI;
    positions[i * 3] = r * Math.sin(phi) * Math.cos(theta);
    positions[i * 3 + 1] = r * Math.sin(phi) * Math.sin(theta);
    positions[i * 3 + 2] = r * Math.cos(phi);

    // 랜덤 방향의 고속 속도 (실시간 시뮬레이션용)
    const speed = 3 + Math.random() * 7; // 빠른 움직임
    const vTheta = Math.random() * Math.PI * 2;
    const vPhi = Math.random() * Math.PI;
    velocities[i * 3] = speed * Math.sin(vPhi) * Math.cos(vTheta);
    velocities[i * 3 + 1] = speed * Math.sin(vPhi) * Math.sin(vTheta);
    velocities[i * 3 + 2] = speed * Math.cos(vPhi);

    // 입자 타입 할당 및 색상
    const type = Math.floor(Math.random() * 4);
    types[i] = type;
    if (type === 0) {
      // 업 쿼크: 빨강
      colors[i * 3] = 1.0;
      colors[i * 3 + 1] = 0.2;
      colors[i * 3 + 2] = 0.2;
    } else if (type === 1) {
      // 다운 쿼크: 초록
      colors[i * 3] = 0.2;
      colors[i * 3 + 1] = 1.0;
      colors[i * 3 + 2] = 0.2;
    } else if (type === 2) {
      // 스트레인지 쿼크: 파랑
      colors[i * 3] = 0.2;
      colors[i * 3 + 1] = 0.2;
      colors[i * 3 + 2] = 1.0;
    } else {
      // 글루온: 노랑
      colors[i * 3] = 1.0;
      colors[i * 3 + 1] = 1.0;
      colors[i * 3 + 2] = 0.2;
    }
  }
  geometry.setAttribute("position", new THREE.BufferAttribute(positions, 3));
  geometry.setAttribute("color", new THREE.BufferAttribute(colors, 3));
  const material = new THREE.PointsMaterial({
    size: 1.2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.8
  });
  const points = new THREE.Points(geometry, material);
  points.userData.velocities = velocities;
  points.userData.types = types;
  points.userData.isPhysicsSimulation = true;
  group.add(points);
  return {
    group,
    velocities,
    positions
  };
}

/**
 * 2️⃣ 쿼크 결합 → 양성자/중성자 (2.5초)
 * 3개 쿼크가 점진적으로 모여드는 모습
 * 오렌지색 결합선이 강하게 결합됨을 표현
 * 진행도(%)에 따라 변화
 */
export function createQuarkCombination(stageProgress) {
  const group = new THREE.Group();

  // 100개의 하드론 형성 과정 (각각 3개 쿼크씩)
  const numHadronGroups = 100000;

  // 쿼크 위치 및 색상
  const quarkGeometry = new THREE.BufferGeometry();
  const quarkPositions = new Float32Array(numHadronGroups * 3 * 3); // 3쿼크 x 3좌표
  const quarkColors = new Float32Array(numHadronGroups * 3 * 3);

  // 형성된 하드론 (양성자/중성자)
  const hadronGeometry = new THREE.BufferGeometry();
  const hadronPositions = new Float32Array(numHadronGroups * 3);
  const hadronColors = new Float32Array(numHadronGroups * 3);

  // 결합선 (쿼크 사이 강한 상호작용 표현)
  const lineGeometry = new THREE.BufferGeometry();
  const linePositions = [];
  const lineColors = [];
  for (let i = 0; i < numHadronGroups; i++) {
    // 하드론의 중심 위치
    const hadronX = (Math.random() - 0.5) * 1000;
    const hadronY = (Math.random() - 0.5) * 1000;
    const hadronZ = (Math.random() - 0.5) * 1000;
    hadronPositions[i * 3] = hadronX;
    hadronPositions[i * 3 + 1] = hadronY;
    hadronPositions[i * 3 + 2] = hadronZ;

    // 하드론의 종류 (양성자 vs 중성자)
    const isProton = Math.random() > 0.5;
    if (isProton) {
      hadronColors[i * 3] = 1.0;
      hadronColors[i * 3 + 1] = 0.1;
      hadronColors[i * 3 + 2] = 0.1;
    } else {
      hadronColors[i * 3] = 0.1;
      hadronColors[i * 3 + 1] = 0.1;
      hadronColors[i * 3 + 2] = 1.0;
    }

    // 3개의 쿼크가 모여드는 과정
    const quarkPositionsThree = [];
    for (let q = 0; q < 3; q++) {
      const angle = q / 3 * Math.PI * 2;
      // 진행도에 따라 쿼크가 모여듦
      const distance = (1 - stageProgress) * 120 + stageProgress * 10;
      const qx = hadronX + Math.cos(angle) * distance;
      const qy = hadronY + Math.sin(angle) * distance;
      const qz = hadronZ + (Math.random() - 0.5) * distance;
      quarkPositions[(i * 3 + q) * 3] = qx;
      quarkPositions[(i * 3 + q) * 3 + 1] = qy;
      quarkPositions[(i * 3 + q) * 3 + 2] = qz;
      quarkPositionsThree.push([qx, qy, qz]);

      // 쿼크 색상 (3가지 타입)
      const quarkType = q;
      if (quarkType === 0) {
        quarkColors[(i * 3 + q) * 3] = 1.0; // 빨강
        quarkColors[(i * 3 + q) * 3 + 1] = 0.2;
        quarkColors[(i * 3 + q) * 3 + 2] = 0.2;
      } else if (quarkType === 1) {
        quarkColors[(i * 3 + q) * 3] = 0.2; // 초록
        quarkColors[(i * 3 + q) * 3 + 1] = 1.0;
        quarkColors[(i * 3 + q) * 3 + 2] = 0.2;
      } else {
        quarkColors[(i * 3 + q) * 3] = 0.2; // 파랑
        quarkColors[(i * 3 + q) * 3 + 1] = 0.2;
        quarkColors[(i * 3 + q) * 3 + 2] = 1.0;
      }
    }

    // 3개 쿼크를 연결하는 오렌지 결합선
    if (i % 100 === 0) {
      // 성능 최적화: 일부만 그리기
      for (let q = 0; q < 3; q++) {
        const nextQ = (q + 1) % 3;
        linePositions.push(quarkPositionsThree[q][0], quarkPositionsThree[q][1], quarkPositionsThree[q][2], quarkPositionsThree[nextQ][0], quarkPositionsThree[nextQ][1], quarkPositionsThree[nextQ][2]);
        const orangeIntensity = stageProgress;
        lineColors.push(1.0 * orangeIntensity, 0.5 * orangeIntensity, 0.0, 1.0 * orangeIntensity, 0.5 * orangeIntensity, 0.0);
      }
    }
  }

  // 쿼크 렌더링
  quarkGeometry.setAttribute("position", new THREE.BufferAttribute(quarkPositions, 3));
  quarkGeometry.setAttribute("color", new THREE.BufferAttribute(quarkColors, 3));
  const quarkMaterial = new THREE.PointsMaterial({
    size: 2 + stageProgress,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 1 - stageProgress * 0.3 // 진행에 따라 투명해짐
  });
  const quarkPoints = new THREE.Points(quarkGeometry, quarkMaterial);
  group.add(quarkPoints);

  // 결합선 렌더링
  if (linePositions.length > 0) {
    lineGeometry.setAttribute("position", new THREE.BufferAttribute(new Float32Array(linePositions), 3));
    lineGeometry.setAttribute("color", new THREE.BufferAttribute(new Float32Array(lineColors), 3));
    const lineMaterial = new THREE.LineBasicMaterial({
      vertexColors: true,
      transparent: true,
      opacity: 0.3 + stageProgress * 0.5,
      linewidth: 2
    });
    const lines = new THREE.LineSegments(lineGeometry, lineMaterial);
    group.add(lines);
  }

  // 형성된 하드론 렌더링
  hadronGeometry.setAttribute("position", new THREE.BufferAttribute(hadronPositions, 3));
  hadronGeometry.setAttribute("color", new THREE.BufferAttribute(hadronColors, 3));
  const hadronMaterial = new THREE.PointsMaterial({
    size: 4 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: stageProgress * 0.9 // 진행에 따라 나타남
  });
  const hadronPoints = new THREE.Points(hadronGeometry, hadronMaterial);
  group.add(hadronPoints);
  return group;
}

/**
 * 3️⃣ 핵융합 → 원자핵 형성 (2.5초)
 * 양성자와 중성자가 융합되는 과정
 * 초반: 분리된 입자 → 후반: 헬륨/리튬/베릴륨 핵
 */
export function createNucleosynthesis(stageProgress) {
  const group = new THREE.Group();
  const numNuclei = 100000;

  // 개별 양성자/중성자 (융합 전)
  const pnGeometry = new THREE.BufferGeometry();
  const pnPositions = new Float32Array(numNuclei * 2 * 3); // 양성자 + 중성자
  const pnColors = new Float32Array(numNuclei * 2 * 3);

  // 형성된 핵들 (융합 후)
  const nucleusGeometry = new THREE.BufferGeometry();
  const nucleusPositions = new Float32Array(numNuclei * 3);
  const nucleusColors = new Float32Array(numNuclei * 3);
  for (let i = 0; i < numNuclei; i++) {
    // 융합될 핵의 중심
    const nucleusX = (Math.random() - 0.5) * 900;
    const nucleusY = (Math.random() - 0.5) * 900;
    const nucleusZ = (Math.random() - 0.5) * 900;
    nucleusPositions[i * 3] = nucleusX;
    nucleusPositions[i * 3 + 1] = nucleusY;
    nucleusPositions[i * 3 + 2] = nucleusZ;

    // 형성된 핵의 종류 (He-4, Li, Be)
    const nucleusType = i % 3;
    if (nucleusType === 0) {
      // 헬륨-4: 시안색
      nucleusColors[i * 3] = 0.2 + stageProgress * 0.3;
      nucleusColors[i * 3 + 1] = 0.8 + stageProgress * 0.2;
      nucleusColors[i * 3 + 2] = 1.0;
    } else if (nucleusType === 1) {
      // 리튬: 초록색
      nucleusColors[i * 3] = 0.2;
      nucleusColors[i * 3 + 1] = 1.0;
      nucleusColors[i * 3 + 2] = 0.2;
    } else {
      // 베릴륨: 노란색
      nucleusColors[i * 3] = 1.0;
      nucleusColors[i * 3 + 1] = 0.9;
      nucleusColors[i * 3 + 2] = 0.2;
    }

    // 양성자 (빨강) - 진행에 따라 가까워짐
    const protonDistance = (1 - stageProgress) * 100 + stageProgress * 15;
    const protonAngle = Math.random() * Math.PI * 2;
    pnPositions[i * 2 * 3] = nucleusX + Math.cos(protonAngle) * protonDistance;
    pnPositions[i * 2 * 3 + 1] = nucleusY + Math.sin(protonAngle) * protonDistance;
    pnPositions[i * 2 * 3 + 2] = nucleusZ + (Math.random() - 0.5) * protonDistance;
    pnColors[i * 2 * 3] = 1.0;
    pnColors[i * 2 * 3 + 1] = 0.1;
    pnColors[i * 2 * 3 + 2] = 0.1;

    // 중성자 (파랑) - 반대편에서 접근
    const neutronDistance = (1 - stageProgress) * 100 + stageProgress * 15;
    const neutronAngle = protonAngle + Math.PI + Math.random() * 0.3;
    pnPositions[i * 2 * 3 + 3] = nucleusX + Math.cos(neutronAngle) * neutronDistance;
    pnPositions[i * 2 * 3 + 4] = nucleusY + Math.sin(neutronAngle) * neutronDistance;
    pnPositions[i * 2 * 3 + 5] = nucleusZ + (Math.random() - 0.5) * neutronDistance;
    pnColors[i * 2 * 3 + 3] = 0.1;
    pnColors[i * 2 * 3 + 4] = 0.1;
    pnColors[i * 2 * 3 + 5] = 1.0;
  }

  // 개별 양성자/중성자 렌더링
  pnGeometry.setAttribute("position", new THREE.BufferAttribute(pnPositions, 3));
  pnGeometry.setAttribute("color", new THREE.BufferAttribute(pnColors, 3));
  const pnMaterial = new THREE.PointsMaterial({
    size: 3 + (1 - stageProgress) * 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: (1 - stageProgress) * 0.8 // 진행에 따라 사라짐
  });
  const pnPoints = new THREE.Points(pnGeometry, pnMaterial);
  group.add(pnPoints);

  // 형성된 핵 렌더링
  nucleusGeometry.setAttribute("position", new THREE.BufferAttribute(nucleusPositions, 3));
  nucleusGeometry.setAttribute("color", new THREE.BufferAttribute(nucleusColors, 3));
  const nucleusMaterial = new THREE.PointsMaterial({
    size: 6 + stageProgress * 3,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: stageProgress * 0.9 // 진행에 따라 나타남
  });
  const nucleusPoints = new THREE.Points(nucleusGeometry, nucleusMaterial);
  group.add(nucleusPoints);
  return group;
}

/**
 * 4️⃣ 원자 형성 (3초)
 * 전자들이 궤도를 따라 이동 (Bohr 모델)
 * 초반: 전자가 핵 근처 → 후반: 완성된 궤도
 */
export function createAtomFormation(stageProgress) {
  const group = new THREE.Group();
  const numAtoms = 80000;
  const atomCenters = [];

  // 각 원자의 핵 위치 결정
  for (let i = 0; i < numAtoms; i++) {
    atomCenters.push({
      x: (Math.random() - 0.5) * 1200,
      y: (Math.random() - 0.5) * 1200,
      z: (Math.random() - 0.5) * 1200,
      isHydrogen: Math.random() > 0.3 // 70% 수소, 30% 헬륨
    });
  }

  // 핵 렌더링
  const nucleusGeometry = new THREE.BufferGeometry();
  const nucleusPositions = new Float32Array(numAtoms * 3);
  const nucleusColors = new Float32Array(numAtoms * 3);
  for (let i = 0; i < numAtoms; i++) {
    nucleusPositions[i * 3] = atomCenters[i].x;
    nucleusPositions[i * 3 + 1] = atomCenters[i].y;
    nucleusPositions[i * 3 + 2] = atomCenters[i].z;

    // 핵: 노란색
    nucleusColors[i * 3] = 1.0;
    nucleusColors[i * 3 + 1] = 0.8;
    nucleusColors[i * 3 + 2] = 0.1;
  }
  nucleusGeometry.setAttribute("position", new THREE.BufferAttribute(nucleusPositions, 3));
  nucleusGeometry.setAttribute("color", new THREE.BufferAttribute(nucleusColors, 3));
  const nucleusMaterial = new THREE.PointsMaterial({
    size: 5 + stageProgress * 2,
    vertexColors: true,
    sizeAttenuation: true
  });
  const nucleusPoints = new THREE.Points(nucleusGeometry, nucleusMaterial);
  group.add(nucleusPoints);

  // 궤도 렌더링 (선으로 표현)
  const orbitLineGeometry = new THREE.BufferGeometry();
  const orbitLinePositions = [];

  // 궤도 선 그리기 (일부만)
  for (let i = 0; i < Math.min(numAtoms, 1000); i++) {
    const center = atomCenters[i];
    const orbitRadius = 80 + (center.isHydrogen ? 0 : 50);
    const segments = 32;
    for (let s = 0; s < segments; s++) {
      const angle1 = s / segments * Math.PI * 2;
      const angle2 = (s + 1) / segments * Math.PI * 2;
      const x1 = center.x + Math.cos(angle1) * orbitRadius * stageProgress;
      const y1 = center.y + Math.sin(angle1) * orbitRadius * stageProgress;
      const z1 = center.z;
      const x2 = center.x + Math.cos(angle2) * orbitRadius * stageProgress;
      const y2 = center.y + Math.sin(angle2) * orbitRadius * stageProgress;
      const z2 = center.z;
      orbitLinePositions.push(x1, y1, z1, x2, y2, z2);
    }
  }
  if (orbitLinePositions.length > 0) {
    orbitLineGeometry.setAttribute("position", new THREE.BufferAttribute(new Float32Array(orbitLinePositions), 3));
    const orbitLineMaterial = new THREE.LineBasicMaterial({
      color: 0x5088ff,
      transparent: true,
      opacity: 0.3 * stageProgress,
      linewidth: 1
    });
    const orbitLines = new THREE.LineSegments(orbitLineGeometry, orbitLineMaterial);
    group.add(orbitLines);
  }

  // 전자 렌더링 (궤도를 따라 이동)
  const electronGeometry = new THREE.BufferGeometry();
  const totalElectrons = Math.floor(numAtoms * 1.3);
  const electronPositions = new Float32Array(totalElectrons * 3);
  const electronColors = new Float32Array(totalElectrons * 3);
  let electronIdx = 0;
  const currentTime = Date.now() * 0.001; // 시간 (초 단위)

  for (let i = 0; i < numAtoms; i++) {
    const center = atomCenters[i];
    const numElectrons = center.isHydrogen ? 1 : 2;
    const orbitRadius = 80 + (center.isHydrogen ? 0 : 50);
    for (let e = 0; e < numElectrons && electronIdx < totalElectrons; e++) {
      // 궤도 상의 위치
      const baseAngle = e / numElectrons * Math.PI * 2;
      const orbitalPlaneAngle = e * 0.5 * Math.PI; // 다른 궤도 평면

      // 시간 기반 애니메이션 (궤도 회전)
      const time = currentTime * (e + 1) * 0.5;
      const angle = baseAngle + time;

      // 3D 궤도 좌표 (회전하는 타원)
      const x = Math.cos(angle) * Math.cos(orbitalPlaneAngle) * orbitRadius * stageProgress;
      const y = Math.sin(angle) * orbitRadius * stageProgress;
      const z = Math.cos(angle) * Math.sin(orbitalPlaneAngle) * orbitRadius * stageProgress;
      electronPositions[electronIdx * 3] = center.x + x;
      electronPositions[electronIdx * 3 + 1] = center.y + y;
      electronPositions[electronIdx * 3 + 2] = center.z + z;

      // 전자: 청록색
      electronColors[electronIdx * 3] = 0.2 + stageProgress * 0.5;
      electronColors[electronIdx * 3 + 1] = 0.9 + stageProgress * 0.1;
      electronColors[electronIdx * 3 + 2] = 1.0;
      electronIdx++;
    }
  }
  electronGeometry.setAttribute("position", new THREE.BufferAttribute(electronPositions, 3));
  electronGeometry.setAttribute("color", new THREE.BufferAttribute(electronColors, 3));
  const electronMaterial = new THREE.PointsMaterial({
    size: 2.5 + stageProgress * 1.5,
    vertexColors: true,
    sizeAttenuation: true,
    transparent: true,
    opacity: 0.2 + stageProgress * 0.6 // 진행에 따라 명확해짐
  });
  const electronPoints = new THREE.Points(electronGeometry, electronMaterial);
  // 매 프레임 업데이트를 위한 플래그
  electronPoints.userData.isAnimated = true;
  electronPoints.userData.atomCenters = atomCenters;
  group.add(electronPoints);
  return group;
}

/**
 * 빅뱅 교육용 단계 정보
 */
export const educationalBigBangStages = [{
  id: 0,
  name: "쿼크-글루온 플라즈마",
  timeRange: "10⁻¹² 초 (1 피코초)",
  koreanTime: "우주 1조분의 1초",
  description: "우주가 극도로 뜨거워 쿼크와 글루온이 자유롭게 움직이고 있습니다. 이들은 아직 결합되지 않은 상태입니다.",
  color: 0xff6b6b,
  duration: 2000
}, {
  id: 1,
  name: "쿼크 결합 → 양성자/중성자",
  timeRange: "10⁻⁶ 초 (1 마이크로초)",
  koreanTime: "우주 100만분의 1초",
  description: "온도가 낮아지면서 쿼크 3개가 결합하여 양성자와 중성자가 형성됩니다. 강한 핵력에 의해 결합됩니다.",
  color: 0x4ecdc4,
  duration: 2500
}, {
  id: 2,
  name: "핵융합 → 원자핵 형성",
  timeRange: "1-3 분",
  koreanTime: "우주 처음 3분",
  description: "양성자와 중성자가 결합하여 헬륨-4, 리튬 등 가벼운 원소의 핵이 형성됩니다. 이를 빅뱅 핵합성이라고 합니다.",
  color: 0x95e77d,
  duration: 2500
}, {
  id: 3,
  name: "원자 형성",
  timeRange: "38만 년",
  koreanTime: "우주 38만 년",
  description: "우주가 충분히 식으면서 전자가 핵 주위를 돌기 시작합니다. 중성 원자(수소, 헬륨)가 형성되고 우주가 투명해집니다.",
  color: 0xb0a0ff,
  duration: 3000
}];
export function getEducationalStageInfo(stageId) {
  return educationalBigBangStages[stageId];
}
export function getTotalEducationalBigBangDuration() {
  return educationalBigBangStages.reduce((sum, stage) => sum + stage.duration, 0);
}

